22	// US-056 — Lister Inbox, Applications sub-tab. Calls the
23	// `list_my_applications_as_lister` SECURITY DEFINER RPC (companion migration
24	// `us_056_list_my_applications_as_lister_rpc`) which joins applications →
25	// listings → users → creator_profiles → social_links under an explicit
26	// `listings.lister_id = current_user_id()` ownership gate and returns one
27	// flat row per application — creator username + platform handles + follower
28	// counts + IG avg views + pitch preview. Same list-my-rows pattern as
29	// US-043 / US-054 (Codebase Pattern #118).
30	//
31	// Segments: Pending / Approved / Rejected per AC. The RPC already excludes
32	// withdrawn + cancelled_listing_edit + cancelled_listing_closed — those are
33	// creator-initiated or cascade-driven cancellations that don't require
34	// lister review. They surface on the campaign-scoped detail screen
35	// (US-057+), not the inbox.
36	//
37	// Grouping: per docs/design.md §3.2 the inbox groups rows by campaign with
38	// inline SectionHeader separators. The RPC returns rows in
39	// `created_at desc`, so within each group rows remain recency-ordered; the
40	// group order is driven by the most-recent application within each group.
41	//
42	// Realtime INSERT subscription: applications is already in the
43	// supabase_realtime publication (US-044). We subscribe with no client
44	// filter because applications has no lister_id column — the
45	// `applications_lister_read` RLS policy is the join-through-listings
46	// security boundary (Codebase Pattern #123). Because the raw INSERT
47	// payload lacks the joined creator + platform metrics, on each insert we
48	// re-run the RPC rather than patching locally. A toast ("New application
49	// received", info variant) gives the lister an in-app cue.
50	
51	type ApplicationStatus = Database['public']['Enums']['application_status'];
52	type Segment = 'pending' | 'approved' | 'rejected';
53	type Row = Database['public']['Functions']['list_my_applications_as_lister']['Returns'][number];
54	
55	// Compile-time exhaustive mapping: if a new enum value is added the
56	// compiler flags the missing bucket (Codebase Pattern #121). The three
57	// enum values the RPC filters out are intentionally absent — they cannot
58	// reach this screen.
59	const STATUS_BUCKET: Record<
60	  Exclude<
61	    ApplicationStatus,
62	    'withdrawn' | 'cancelled_listing_edit' | 'cancelled_listing_closed'
63	  >,
64	  Segment
65	> = {
66	  pending: 'pending',
67	  approved: 'approved',
68	  rejected: 'rejected',
69	};
70	
71	const SEGMENTS: readonly { key: Segment; label: string }[] = [
72	  { key: 'pending', label: 'Pending' },
73	  { key: 'approved', label: 'Approved' },
74	  { key: 'rejected', label: 'Rejected' },
75	];
76	
77	type SegmentControlProps = {
78	  active: Segment;
79	  counts: Record<Segment, number>;
80	  onChange: (next: Segment) => void;
81	};
82	
83	function SegmentControl({ active, counts, onChange }: SegmentControlProps) {
84	  return (
85	    <View style={styles.segmentRow} accessibilityRole="tablist">
86	      {SEGMENTS.map((s) => (
87	        <SegmentButton
88	          key={s.key}
89	          label={`${s.label} (${counts[s.key]})`}
90	          selected={active === s.key}
91	          onPress={() => onChange(s.key)}
92	          testID={`segment-${s.key}`}
93	        />
94	      ))}
95	    </View>
96	  );
97	}
98	
99	type SegmentButtonProps = {
100	  label: string;
101	  selected: boolean;
102	  onPress: () => void;
103	  testID?: string;
104	};
105	
106	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
107	  const bg = selected ? colors.primarySoft : colors.surface;
108	  const textColor = selected ? colors.primaryDeep : colors.ink;
109	  return (
110	    <Pressable
111	      onPress={onPress}
112	      accessibilityRole="tab"
113	      accessibilityState={{ selected }}
114	      accessibilityLabel={label}
115	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
116	      testID={testID}
117	    >
118	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
119	        {label}
120	      </Text>
121	    </Pressable>
122	  );
123	}
124	
125	// SectionHeader per docs/design.md §6 — kept inline until a second consumer
126	// shows up. The `══════ Label ══════` visual uses horizontal rules bracketing
127	// the title; a single flex row with 2-px borders keeps it token-friendly.
128	function SectionHeader({ title }: { title: string }) {
129	  return (
130	    <View style={styles.sectionHeaderRow} accessibilityRole="header">
131	      <View style={styles.sectionRule} />
132	      <Text
133	        style={[textStyles.micro, { color: colors.ink }]}
134	        allowFontScaling={false}
135	        numberOfLines={1}
136	      >
137	        {title}
138	      </Text>
139	      <View style={styles.sectionRule} />
140	    </View>
141	  );
142	}
143	
144	function bucketFor(status: ApplicationStatus): Segment | null {
145	  if (status === 'withdrawn') return null;
146	  if (status === 'cancelled_listing_edit') return null;
147	  if (status === 'cancelled_listing_closed') return null;
148	  return STATUS_BUCKET[status];
149	}
