1	-- =========================================================
2	-- US-009: RLS policies on every user-data table
3	-- Source of truth: docs/tech-architecture.md §4.4 + §4.7 block 14.
4	--
5	-- Behavior:
6	--   * Per-tenant scoping via public.current_user_id() → auth.jwt() ->> 'sub'.
7	--   * RLS is (re)enabled on all 15 tables enumerated in §4.7 block 14.
8	--   * public.events has no policy (RLS + zero policies + revoke = deny);
9	--     service-role writes bypass via security-definer functions.
10	--   * Story AC named `listing_pre_conditions` + `listing_post_conditions`, but
11	--     the spec uses a single `listing_conditions` table discriminated by kind
12	--     (§4.7 block 8). Policies attach to `listing_conditions` per spec.
13	--
14	-- submission_reuse_view handoff (Codebase Patterns):
15	--   The view at public.submission_reuse_view (us_006) runs with
16	--   security_invoker = on to clear the `security_definer_view` advisor, but
17	--   under that mode a lister's RLS on submissions would mask cross-lister
18	--   reuse counts — defeating the ReuseBadge. We drop the view and replace it
19	--   with public.submission_reuse_count(uuid), a SECURITY DEFINER function that
20	--   performs its own caller-authorization check (must own the listing behind
21	--   the submission) and then counts across all submissions, bypassing RLS.
22	--   The UI stories (US-058, US-065) call this via PostgREST RPC.
23	-- =========================================================
24	
25	-- ---------------- Helpers (JWT → current user / role) ----------------
26	create or replace function public.current_user_id()
27	returns uuid
28	language sql
29	stable
30	set search_path = ''
31	as $$
32	  select nullif(auth.jwt() ->> 'sub', '')::uuid
33	$$;
34	
35	create or replace function public.current_user_role()
36	returns public.user_role
37	language sql
38	stable
39	set search_path = ''
40	as $$
41	  select nullif(auth.jwt() ->> 'role', '')::public.user_role
42	$$;
43	
44	revoke all on function public.current_user_id() from public;
45	revoke all on function public.current_user_role() from public;
46	grant execute on function public.current_user_id() to anon, authenticated, service_role;
47	grant execute on function public.current_user_role() to anon, authenticated, service_role;
48	
49	-- ---------------- Enable RLS (idempotent; Supabase already auto-enabled) ----------------
50	alter table public.users              enable row level security;
51	alter table public.creator_profiles   enable row level security;
52	alter table public.lister_profiles    enable row level security;
53	alter table public.social_links       enable row level security;
54	alter table public.metric_snapshots   enable row level security;
55	alter table public.listings           enable row level security;
56	alter table public.listing_versions   enable row level security;
57	alter table public.listing_conditions enable row level security;
58	alter table public.sample_videos      enable row level security;
59	alter table public.applications       enable row level security;
60	alter table public.submissions        enable row level security;
61	alter table public.submission_videos  enable row level security;
62	alter table public.notifications      enable row level security;
63	alter table public.push_tokens        enable row level security;
64	alter table public.events             enable row level security;
65	
66	-- ---------------- users ----------------
67	drop policy if exists users_self_select on public.users;
68	create policy users_self_select on public.users for select
69	  using (id = public.current_user_id());
70	
71	drop policy if exists users_self_update on public.users;
72	create policy users_self_update on public.users for update
73	  using (id = public.current_user_id())
74	  with check (id = public.current_user_id());
75	
76	-- ---------------- creator_profiles ----------------
77	drop policy if exists creator_profiles_self_rw on public.creator_profiles;
78	create policy creator_profiles_self_rw on public.creator_profiles
79	  for all
80	  using (user_id = public.current_user_id())
81	  with check (user_id = public.current_user_id());
82	
83	drop policy if exists creator_profiles_lister_read on public.creator_profiles;
84	create policy creator_profiles_lister_read on public.creator_profiles
85	  for select using (
86	    exists (
87	      select 1
88	      from public.applications a
89	      join public.listings l on l.id = a.listing_id
90	      where a.creator_id = public.creator_profiles.user_id
91	        and l.lister_id = public.current_user_id()
92	    )
93	  );
94	
95	-- ---------------- lister_profiles ----------------
96	drop policy if exists lister_profiles_self_rw on public.lister_profiles;
97	create policy lister_profiles_self_rw on public.lister_profiles
98	  for all
99	  using (user_id = public.current_user_id())
100	  with check (user_id = public.current_user_id());

1	// Eligibility engine — shared between get-listing-detail and
2	// apply-to-listing (US-039 + US-041).
3	//
4	// Pre-conditions are evaluated against the creator's denormalized metrics
5	// from `creator_profiles`. Only pre-conditions gate apply-time eligibility
6	// per docs/tech-architecture.md §6.3. Post-conditions are returned by
7	// get-listing-detail for UI display and evaluated later on submissions.
8	//
9	// Fail-closed on missing metrics (§3d): when the creator hasn't been
10	// scraped yet (or a specific platform field is NULL), the pre-condition
11	// keyed on that field fails. Same rule extends to pre-condition rows with
12	// an unknown operator or unreadable metric — treat as failed rather than
13	// silently pass, so a future mis-migrated row can't flip a listing to
14	// eligible by accident.
15	
16	export type Platform = "tiktok" | "instagram";
17	export type ConditionKind = "pre" | "post";
18	
19	export interface ConditionRow {
20	  id: string;
21	  listing_version_id: string;
22	  kind: ConditionKind;
23	  metric: string;
24	  platform: Platform | null;
25	  operator: string;
26	  numeric_threshold: string | number | null;
27	  text_threshold: string | null;
28	  bool_threshold: boolean | null;
29	  created_at: string;
30	}
31	
32	export interface CreatorProfileRow {
33	  tiktok_follower_count: number | null;
34	  tiktok_avg_views_last_10: number | null;
35	  tiktok_total_likes: number | null;
36	  tiktok_video_count: number | null;
37	  tiktok_is_verified: boolean | null;
38	  instagram_follower_count: number | null;
39	  instagram_avg_views_last_10: number | null;
40	  instagram_media_count: number | null;
41	}
42	
43	export interface FailedCondition {
44	  metric: string;
45	  platform: Platform | null;
46	  required: number | boolean;
47	  actual: number | boolean | null;
48	}
49	
50	export const EMPTY_CREATOR_METRICS: CreatorProfileRow = {
51	  tiktok_follower_count: null,
52	  tiktok_avg_views_last_10: null,
53	  tiktok_total_likes: null,
54	  tiktok_video_count: null,
55	  tiktok_is_verified: null,
56	  instagram_follower_count: null,
57	  instagram_avg_views_last_10: null,
58	  instagram_media_count: null,
59	};
60	
61	// Evaluate a single pre-condition against the creator's denormalized
62	// metrics. Returns `null` on pass, or the failed-condition detail on fail.
63	// Missing data (null actual for a numeric threshold) fails closed per §3d.
64	export function evaluatePreCondition(
65	  condition: ConditionRow,
66	  metrics: CreatorProfileRow,
67	): FailedCondition | null {
68	  const { metric, platform, operator } = condition;
69	  if (operator === "gte") {
70	    const required = Number(condition.numeric_threshold);
71	    // Malformed numeric_threshold (NULL or non-numeric) fails closed per §3d —
72	    // schema CHECKs should prevent this today, but a future mis-migrated row
73	    // must not flip a condition to "always passes" just because it's unreadable.
74	    if (!Number.isFinite(required)) {
75	      return { metric, platform, required: 0, actual: null };
76	    }
77	    const actual = readNumericMetric(metrics, platform, metric);
78	    if (actual === null || actual < required) {
79	      return { metric, platform, required, actual };
80	    }
81	    return null;
82	  }
83	  if (operator === "bool") {
84	    const required = condition.bool_threshold === true;
85	    const actual = readBoolMetric(metrics, platform, metric);
86	    if (actual !== required) {
87	      return { metric, platform, required, actual };
88	    }
89	    return null;
90	  }
91	  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
92	  // are reserved for post-conditions today (e.g. post_must_mention uses
93	  // 'contains'), so this branch should be unreachable; if a future migration
94	  // misplaces an operator, we'd rather block an apply than silently allow it.
95	  console.warn("pre-condition with unknown operator treated as failed", {
96	    condition_id: condition.id,
97	    operator,
98	    metric,
99	    platform,
100	  });
101	  const parsed = Number(condition.numeric_threshold);
102	  return {
103	    metric,
104	    platform,
105	    required: Number.isFinite(parsed) ? parsed : 0,
106	    actual: null,
107	  };
108	}
109	
110	// Evaluate every pre-condition and return the (possibly empty) list of
111	// failures. Post-conditions are ignored.
112	export function evaluatePreConditions(
113	  conditions: ConditionRow[],
114	  metrics: CreatorProfileRow,
115	): FailedCondition[] {
116	  const failed: FailedCondition[] = [];
117	  for (const c of conditions) {
118	    if (c.kind !== "pre") continue;
119	    const miss = evaluatePreCondition(c, metrics);
120	    if (miss) failed.push(miss);
121	  }
122	  return failed;
123	}
124	
125	function readNumericMetric(
126	  metrics: CreatorProfileRow,
127	  platform: Platform | null,
128	  metric: string,
129	): number | null {
130	  if (platform === "tiktok") {
131	    switch (metric) {
132	      case "min_followers":
133	        return metrics.tiktok_follower_count;
134	      case "min_avg_views_last_n":
135	        return metrics.tiktok_avg_views_last_10;
136	      case "min_total_likes":
137	        return metrics.tiktok_total_likes;
138	      case "min_videos_posted":
139	        return metrics.tiktok_video_count;
140	      default:
141	        return null;
142	    }
143	  }
144	  if (platform === "instagram") {
145	    switch (metric) {
146	      case "min_followers":
147	        return metrics.instagram_follower_count;
148	      case "min_avg_views_last_n":
149	        return metrics.instagram_avg_views_last_10;
150	      case "min_videos_posted":
151	        return metrics.instagram_media_count;
152	      default:
153	        return null;
154	    }
155	  }
156	  return null;
157	}
158	
159	function readBoolMetric(
160	  metrics: CreatorProfileRow,
161	  platform: Platform | null,
162	  metric: string,
163	): boolean | null {
164	  if (platform === "tiktok" && metric === "verified_only") {
165	    return metrics.tiktok_is_verified;
166	  }
167	  return null;
168	}
